(* Generate a random (0,1)-matrix of size n x n with probability p of a 1 *)
n = 5; (* Example size *)
p = 0.5; (* Example probability *)
matrix = RandomInteger[BernoulliDistribution[p], {n, n}];

(* Function to find connected components (s-clusters) in the matrix *)
FindClusters[mat_] := Module[{visited, clusters},
  visited = ConstantArray[False, Dimensions[mat]];
  clusters = {},

  Do[
   If[! visited[[i, j]] && mat[[i, j]] == 1,
    cluster = {};
    stack = {{i, j}};
    visited[[i, j]] = True;

    While[Length[stack] > 0,
     {x, y} = First[stack];
     stack = Rest[stack];
     AppendTo[cluster, {x, y}];

     (* Check adjacent cells: up, down, left, right *)
     Do[
      nx = x + dx; ny = y + dy;
      If[nx >= 1 && nx <= n && ny >= 1 && ny <= n && 
       mat[[nx, ny]] == 1 && ! visited[[nx, ny]],
       visited[[nx, ny]] = True;
       PrependTo[stack, {nx, ny}];
       ],
      {dx, dy} 
      {
       {-1, 0}, {1, 0}, {0, -1}, {0, 1}
      }
     ];
    ];
    AppendTo[clusters, cluster];
   ],
   {i, n}, {j, n}
  ];
  clusters
];

(* Count the number of s-clusters *)
clusters = FindClusters[matrix];
numClusters = Length[clusters];

Print["Matrix:"];
Print[matrix];
Print["Number of s-clusters: ", numClusters];
